/**
 * Query keys for API endpoints defined in the OpenAPI spec are generated by
 * @hey-api/openapi-ts and live in `@/lib/api/@tanstack/react-query.gen`:
 * getDevicesQueryKey(), getDeviceAddressesQueryKey({ path: { device_id } }),
 * getCurrentUserQueryKey(), etc. Use those for cache invalidation and key matching.
 *
 * Add custom keys here only for endpoints not yet covered by the generated
 * React Query layer.
 */
export const queryKeys = {} as const;
